import{_ as i,o as s,c as e,ag as l}from"./chunks/framework.D2Ob5GRY.js";const k=JSON.parse('{"title":"下载安装包","description":"","frontmatter":{},"headers":[],"relativePath":"quickstart/download.md","filePath":"quickstart/download.md"}'),t={name:"quickstart/download.md"};function n(o,a,h,r,d,c){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="下载安装包" tabindex="-1">下载安装包 <a class="header-anchor" href="#下载安装包" aria-label="Permalink to &quot;下载安装包&quot;">​</a></h1><blockquote><p>在下载中心获取对应套餐的 LinScio AI 安装包。</p></blockquote><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><ul><li>已在门户完成注册并激活（或已获得授权码并激活）。</li></ul><h2 id="在「下载中心」获取对应套餐的安装包" tabindex="-1">在「下载中心」获取对应套餐的安装包 <a class="header-anchor" href="#在「下载中心」获取对应套餐的安装包" aria-label="Permalink to &quot;在「下载中心」获取对应套餐的安装包&quot;">​</a></h2><ol><li>登录门户，进入「用户中心」。</li><li>点击「前往下载页」或通过导航栏「下载」进入下载页。</li><li>根据套餐选择对应安装包（如个人版 / 团队版），点击下载。</li></ol><h2 id="安装包内容说明-解压后的文件结构" tabindex="-1">安装包内容说明（解压后的文件结构） <a class="header-anchor" href="#安装包内容说明-解压后的文件结构" aria-label="Permalink to &quot;安装包内容说明（解压后的文件结构）&quot;">​</a></h2><p>（此处为占位：根据实际安装包结构填写，如 <code>linscio-ai-v1.x.x/</code> 下含 <code>install.sh</code>、<code>docker-compose.yml</code>、<code>.env.example</code> 等。）</p><h2 id="sha256-校验-验证下载完整性" tabindex="-1">SHA256 校验（验证下载完整性） <a class="header-anchor" href="#sha256-校验-验证下载完整性" aria-label="Permalink to &quot;SHA256 校验（验证下载完整性）&quot;">​</a></h2><p>若门户或安装包说明中提供了 SHA256 校验值，可在本地执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Linux / macOS 示例</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sha256sum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> linscio-ai-v1.x.x.tar.gz</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 或</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shasum</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 256</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> linscio-ai-v1.x.x.tar.gz</span></span></code></pre></div><p>将输出与提供的校验值对比，一致则下载完整。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/quickstart/first-deployment.html">首次部署</a></li><li><a href="/docs/quickstart/configure-llm-basic.html">配置 LLM（首次必做）</a></li></ul>`,14)])])}const u=i(t,[["render",n]]);export{k as __pageData,u as default};
